#version 330 core

in vec3 v_world_position;
in vec3 v_normal;
in vec3 v_color;
out vec4 fragColor;

uniform vec3 u_view_position;
uniform vec3 u_dir_light_direction;
uniform vec3 u_dir_light_color;
uniform vec3 u_point_light_position;
uniform vec3 u_point_light_color;
uniform float u_point_light_enabled;
uniform vec3 u_material_ambient;
uniform vec3 u_material_specular;
uniform float u_material_shininess;
uniform vec3 u_material_emissive;

void main() {
    vec3 N = normalize(v_normal);
    vec3 V = normalize(u_view_position - v_world_position);
    vec3 albedo = v_color;

    vec3 result = u_material_ambient * albedo + u_material_emissive;

    vec3 Ld = normalize(-u_dir_light_direction);
    float diff = max(dot(N, Ld), 0.0);
    vec3 H = normalize(Ld + V);
    float spec = pow(max(dot(N, H), 0.0), u_material_shininess);
    result += diff * albedo * u_dir_light_color;
    result += spec * u_material_specular * u_dir_light_color;

    if (u_point_light_enabled > 0.5) {
        vec3 toLight = u_point_light_position - v_world_position;
        float dist = length(toLight);
        vec3 Lp = toLight / max(dist, 0.0001);
        float att = 1.0 / (1.0 + 0.06 * dist + 0.02 * dist * dist);
        diff = max(dot(N, Lp), 0.0);
        H = normalize(Lp + V);
        spec = pow(max(dot(N, H), 0.0), u_material_shininess);
        result += att * (diff * albedo * u_point_light_color);
        result += att * (spec * u_material_specular * u_point_light_color);
    }

    fragColor = vec4(result, 1.0);
}

